import{_ as o}from"./nyalra_kb-7135827b.js";import{_ as d}from"./nyalra_no_mono-8344e451.js";import{_ as h,W as i,X as c,Y as s,Z as e,$ as a,a1 as p,a2 as l,a0 as _,C as r}from"./framework-91490e6a.js";const m={},f=e("figure",null,[e("img",{src:o,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),u={href:"https://tree-novel.com/works/episode/eec32041052fd26eb6d45d52e9f2efb1.html",target:"_blank",rel:"noopener noreferrer"},b=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),x=_('<hr><p>上次是关于房租和住所的话题，所以这次是兼职工作篇。</p><p>我将坦率地写下我之前经历过的兼职工作经历。</p><h2 id="便利店兼职" tabindex="-1"><a class="header-anchor" href="#便利店兼职" aria-hidden="true">#</a> 便利店兼职</h2><p>虽然不推荐，但很容易被录用，特别是在紧急招聘人员的地方。</p><p>根据店铺的不同，外表和工作态度都不太重要。只要你能接受轮班，强调「我每周可以工作○次！」就能被录用。</p><p>工作内容非常辛苦！包括接待客户、整理商品、与同事之间的人际关系以及应对异常客户……总之，休息时间之前一直忙碌。因为没有闲暇时间，所以会感觉时间过得很快，这也是一个好处。</p><p>然而，便利店的性质在白天、下午和夜班时完全不同。</p><p>我几乎都在夜班工作，夜班可以说是疯狂的。毕竟深夜来的客户都很奇怪，而且夜班的同事也很独特。要么是没有学业目标的大学生，要么是因赌博等原因有故事的中年男人，还有外国人。</p><p>根据店铺的不同，你可能会有空闲时间看杂志或吃废弃的便当，这真的很好。工作是否繁忙，取决于你是否能迅速完成工作，因为有时候会有2到3小时只需要接待逛店的客人。</p><p>然而，夜班也会让你失去很多东西。比如生活节奏。由于工作时间是晚上10点到早上8点，下班后就会在早上10点左右入睡。然后在晚上7点左右醒来，再悠闲地准备去夜班。因为几乎不见太阳，生活会变得不健康，你的活力也会迅速流失。因为不能养成从中午开始出门的习惯，也会使你与朋友计划一起玩变得更加困难。</p><p>然而，作为回报，夜班工作会获得比普通工作更多的夜班津贴。如果你更看重钱，这可能是个好选择，但个人来说，既然已经选择了兼职工作这种有点麻烦的体验，为什么不选择能体验到更奇怪的事和交到更奇怪的朋友的呢？</p><p>平静地完成被吩咐的事，并以此为乐的「便利店人」也是有可能存在的。</p><h2 id="日结兼职" tabindex="-1"><a class="header-anchor" href="#日结兼职" aria-hidden="true">#</a> 日结兼职</h2><p>如果你注册了日结兼职，虽然不会受到太多人道关怀，但你可以随时工作，当天就能拿到钱。就像当时的我一样，如果迫切需要快速筹集钱，以防止电费和燃气费停止供应，这是一个推荐的选择。</p><p>然而，我在日结兼职工作中被偷了钱包，结果变得欠钱，所以不应该视上司和同事为朋友。要记住，他们可能和我一样，生活处于临界点，需要拼命维持生计。</p><h2 id="仓库作业" tabindex="-1"><a class="header-anchor" href="#仓库作业" aria-hidden="true">#</a> 仓库作业</h2><p>如果你申请了那种日结的兼职工作，通常会被分配到体力劳动。</p><p>早上早早地聚集在办公室，然后被载上车，送到之前从未去过的工厂区域，从中午工作到晚上。</p><p>坦率地说，这是地狱。巨大的卡车一个接一个地到达仓库，你要不停地搬运里面的货物，然后放到传送带上。没有一刻的休息，当你搬完一个纸箱后，就得赶紧跑去搬下一个。如果你停下来休息，身材强壮的家伙们会瞪着你。这种工作一直重复着直到工作时间结束。</p><p>看起来好像没有什么好处，但你的身体可能会得到锻炼。对于那些喜欢健身的人来说，这可能是一份辛苦但有钱可赚的好工作。从健康角度来看，也许不算太糟糕。</p><p>然而，对我来说，做完这份工作后，我的钱包被偷了......</p><h2 id="搬家" tabindex="-1"><a class="header-anchor" href="#搬家" aria-hidden="true">#</a> 搬家</h2><p>这也是日结兼职之一。</p><p>相比于仓库作业，这要容易一些。当然，这取决于你要帮助的家庭。虽然冰箱很重，但你可以和身材强壮的同事一起搬运，而且在移动的时候可以坐在车上休息（尽管有来自司机的压力），比起仓库作业更值得推荐。不过，作为日结工，你并不能自己选择工作，如果今天被告知要做这个，你就得去做。</p><p>虽然相对于仓库作业要容易一些，但你要小心翼翼地搬运他人珍贵的财物，因此谨慎至关重要。哪怕轻轻碰到墙壁，你也会被同事们责备得不行。如果你不怕这种压力，那可能不错，但对我来说，与其搬运他人的物品，还不如在仓库里忙碌地处理陌生的纸箱更让人精神愉悦。日薪方面，不论是仓库工作还是搬家工作，可能都在1万日元左右。</p><h1 id="呼叫中心" tabindex="-1"><a class="header-anchor" href="#呼叫中心" aria-hidden="true">#</a> 呼叫中心</h1><p>如果注册到供呼叫中心使用的日结兼职中心的话，与前两种体力劳动不同，你可以得到介绍到呼叫中心兼职，只需要不断地打电话。不过，尽管只是不断打电话，时薪却比体力劳动高！</p><p>但是，高时薪有其原因，因为你需要坐着不停地打电话，然后进行针对接听电话的老人的问卷调查。当然，老人突然接到陌生人的电话通常都会有点生气，他们经常会生气地喊：「你谁啊！」甚至挂断电话也不少见。而且，即使你认真回答了问题，也不会有什么回报。</p><p>精神上的痛苦可能是最大的。毕竟，你是在浪费陌生人几分钟的时间。这种行为就像是践踏了老人接听陌生号码电话的善意。</p><p>不过，如果是由年轻可爱的女性的声音打电话的话，对方的态度可能会缓和一些。尽管即使如此，这仍然可能是一份疲劳的工作，但可爱度在一定程度上可以让工作变得更有趣。</p><h2 id="dj活动的前台接待" tabindex="-1"><a class="header-anchor" href="#dj活动的前台接待" aria-hidden="true">#</a> DJ活动的前台接待</h2><p>因为我的朋友在一次动漫主题歌曲活动中当DJ，所以曾经请我帮忙做前台接待。</p><p>这工作相当轻松，坐在椅子上，懒洋洋地等待，当有人进来时，只需要接受他们的钱并递给他们门票。开场时间以外的人潮并不多，你可以和来休息的人闲聊，因为他们已经听够了音乐。此外，你还可以观察DJ们如何在舞池上尝试搭讪女性客人。</p><p>如果一定要说的话，只有一个问题，那就是无论舞池多么热闹，你都不能去看。我对DJ活动本身就不太感兴趣，所以我可以接受这一点，但如果你热爱活动，这种被排斥的感觉可能会让你感到空虚。</p><p>当你的朋友举办某种活动时，你可以说：「我来负责前台接待！」这或许是一份可以考虑的工作。薪水由主办者决定。</p><h2 id="居酒屋工作" tabindex="-1"><a class="header-anchor" href="#居酒屋工作" aria-hidden="true">#</a> 居酒屋工作</h2><p>我在高中的时候曾经做过这份工作，简直是地狱。</p><p>经常被醉酒的客人缠着，老板也非常粗鲁。每天都会听到他大声吼叫：「为什么记不住菜单？」。</p><p>而且，我当时在冲绳。不管是游客还是当地居民，每晚都会狂欢！客人和员工的距离非常近，经常会被邀请一起喝酒。对于老板来说，这是一件让人高兴的事情，但对于只是一名普通的兼职员工来说，这只是一种麻烦。</p><p>如果说这份工作能锻炼人的话，也许是这样。虽然我不太喜欢「年轻时吃的苦是一种投资」的说法，但通过刻意经历这种地狱，可能可以让其他工作相对之下显得轻松一些。毕竟，生活本来就充满了各种困难，所以也可以主动去尝试一下。</p><h2 id="在网络媒体上写作" tabindex="-1"><a class="header-anchor" href="#在网络媒体上写作" aria-hidden="true">#</a> 在网络媒体上写作</h2><p>理所当然，要通过网络媒体获得工作机会的话，有两个选择：要么是「你写的文章被传播出去，引起编辑的注意」，要么是「主动发送稿件/提出企划」。我一直都是前者。因为如果有一篇我想写的文章，我完全可以将它发布在我的博客或者note上。</p><p>然而，我在我的博客上没有添加任何广告链接，所以无论有多少访问量，我都无法从中获得分成。对于当时的我，来自网络媒体的稿酬非常宝贵。感谢这一机会。</p><p>此外，与出版社合作可以进行一些特别的企划，如采访等，甚至更大规模的企划。不同的企划有不同的酬金，显然，在自己经营的媒体上做有趣的事情会吸引更多读者。</p><p>在写稿时，你可以权衡金钱和读者数量。现在想来，如果我当初坦率地加入了广告链接，或许我能够赚更多钱！</p><p>最终，最好的方式是在你自己的账号上发布文章，然后等待来自对你产生兴趣的编辑的联系。试着申请写手招聘网站上的一个职位时，我被要求写三篇糟糕的匿名产品评论（无论如何都要过分赞美，介绍甚至没有用过的商品），而作为回报，只有500日元。这种工作只会在网络上增加垃圾页面。没有任何生产力，反而对世界有害。这会使你的心情变得糟糕，你无需做这样的工作。我当时也立刻拒绝了。</p><h2 id="临床试验" tabindex="-1"><a class="header-anchor" href="#临床试验" aria-hidden="true">#</a> 临床试验</h2><p>临床试验是一份能够获得大量金钱报酬的极佳兼职，作为交换，你会被要求服用尚未上市的药物并成为实验对象。</p><p>很早以前，我也曾在临床试验中入院两个月。在医院里只需要躺着、看漫画和休息，我赚了大约40万日元。真是太棒了！但从某种角度来看，把年轻的时间换成金钱，这可能是效率最低的方式。个人来说，因为可以阅读书籍，我并不觉得这是浪费。我甚至将这段时间看作是「阅读期」。</p><p>我的朋友曾经带着街机游戏手柄来临床试验，然后专注地玩格斗游戏。有一段时间用于专注于掌握一项技能，然后能够获得大量金钱，这真是不可思议。</p><p>不过，现在要参加临床试验通常需要接种疫苗才能获得优先考虑。既然疫苗是免费的，最好还是接种。结果就是，现在临床试验的参与者中，汇集了一大批不寻常的人。这真是令人印象深刻。</p><hr><p>就是这种感觉。大家也通过参与这些艰苦却薪水微薄的工作，将对社会的不满转化为动力吧！</p><hr><p><img src="'+d+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/7e5675ca615452ac774be811b0377197.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/8b452d2c1b1c956a3d09869fa87154c2.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【小樱的书签】数年前，在六本木举办的「樱花展」上购买的书签。如果将这么可爱的书签放在书里，可就不顾读书了吧！尽管一开始没有打开，但最近我终于决定打开它，因为书签终究还是用来标记书页的。这成为了我重新开始阅读时的乐趣。</p></blockquote>',57);function k(g,y){const t=r("ExternalLinkIcon"),n=r("RouterLink");return i(),c("div",null,[s(" more "),f,e("p",null,[a("原文链接："),e("a",u,[a("第37回／にゃるらが体験したアルバイト集"),p(t)])]),e("blockquote",null,[b,e("p",null,[p(n,{to:"/posts/Translate/nyalra_kb_36.html"},{default:l(()=>[a("【奈亚拉面壁自语】第36回｜来东京之后租的公寓和合租房的房租诸事【230725】")]),_:1})])]),x])}const j=h(m,[["render",k],["__file","nyalra_kb_37.html.vue"]]);export{j as default};
